import{_ as t,o as l,c as a,ag as o}from"./chunks/framework.DAAaZ98D.js";const h=JSON.parse('{"title":"路径格式","description":"","frontmatter":{},"headers":[],"relativePath":"docs/path.md","filePath":"docs/path.md"}'),d={name:"docs/path.md"};function c(i,e,n,s,r,p){return l(),a("div",null,[...e[0]||(e[0]=[o(`<h1 id="路径格式" tabindex="-1">路径格式 <a class="header-anchor" href="#路径格式" aria-label="Permalink to &quot;路径格式&quot;">​</a></h1><p>转载自<a href="https://sustech-application.com/" target="_blank" rel="noreferrer">南科大飞跃手册</a></p><p>所有文件采用扁平化的组织形式，不对类型、专业等作任何区分，统一存放在 <code>docs/</code> 下。<code>docs/</code> 被配置为 VitePress 的根目录，并不出现在 URL 中。因此，飞跃手册经验分享的帖子路径格式为：<code>docs/&lt;id&gt;.md</code>，对应的 URL 路径为 <code>/&lt;id&gt;</code>。</p><h2 id="文件名格式" tabindex="-1">文件名格式 <a class="header-anchor" href="#文件名格式" aria-label="Permalink to &quot;文件名格式&quot;">​</a></h2><p>其中，<code>&lt;id&gt;</code> 的格式为 <code>&lt;surname&gt;&lt;first-name-abbr&gt;&lt;year&gt;</code>：</p><ul><li><code>&lt;surname&gt;</code> 为姓氏的全拼写，如「李」姓对应 <code>li</code>。使用复姓的，全拼写所有汉字，如「慕容」对应 <code>murong</code>。</li><li><code>&lt;first-name-abbr&gt;</code> 为名的首字母缩写，如单名「明」的，对应 <code>m</code>；双名「小明」的，对应 <code>xm</code>；双名以上的，以此类推。</li><li><code>&lt;year&gt;</code> 为年级的后两位。如入学年份为 2019 年的，对应 <code>19</code>。</li></ul><p>例如，李小明于 2019 年入学，其分享对应的文件名为 <code>lixm19.md</code>。</p><div class="info custom-block github-alert"><p class="custom-block-title">格式来源</p><p></p><p>这个格式主要启发自南科大邮箱的别名格式，但只取年份的后两位以缩短链接长度。</p></div><p>若是匿名分享，则采用 <code>anon&lt;year&gt;</code> 格式。</p><h2 id="同名同年级情况" tabindex="-1">同名同年级情况 <a class="header-anchor" href="#同名同年级情况" aria-label="Permalink to &quot;同名同年级情况&quot;">​</a></h2><p>若出现同名同年级的情况，或一人有多个投稿的，按上述规则，则文件名也相同，因此需要作出如下区分：</p><ul><li>先进行第一次投稿的作者，可使用标准文件名</li><li>主文件名之外，其他的帖子，不管是同一作者还是不同作者，应按时间顺序排列，在后方添加字母后缀，如 <code>lixm19a</code>、<code>lixm19b</code> 等。</li><li>同一作者有多个帖子的，不论投稿时间先后，其研究生项目申请经验分享应始终拥有主文件名（如该作者先于其他同名同年级作者投稿）</li><li>同年级的匿名作者，先投稿的可使用默认文件名，其他投稿统一按照时间顺序排列添加字母后缀。</li></ul><p>例如，下表中，李小明（甲）和李晓民（乙）同为 19 级本科生，且按时间顺序（从上到下）进行了表格中列举的投稿，则其文件名应如表所示。</p><table tabindex="0"><thead><tr><th style="text-align:center;">作者</th><th style="text-align:center;">投稿内容</th><th style="text-align:left;">文件名</th><th style="text-align:left;">解释</th></tr></thead><tbody><tr><td style="text-align:center;">甲</td><td style="text-align:center;">暑研项目</td><td style="text-align:left;"><code>lixm19a</code></td><td style="text-align:left;">此投稿早于同一作者的申请经验分享，但不能使用主文件名</td></tr><tr><td style="text-align:center;">乙</td><td style="text-align:center;">博士申请</td><td style="text-align:left;"><code>lixm19b</code></td><td style="text-align:left;">李小明的第一次投稿更早，且后续也投稿了申请经验，因此这里不能使用主文件名</td></tr><tr><td style="text-align:center;">甲</td><td style="text-align:center;">硕士申请</td><td style="text-align:left;"><code>lixm19</code></td><td style="text-align:left;">李小明的第一次投稿更早，因此使用主文件名</td></tr><tr><td style="text-align:center;">乙</td><td style="text-align:center;">英语学习</td><td style="text-align:left;"><code>lixm19c</code></td><td style="text-align:left;">按时间顺序添加字母后缀</td></tr></tbody></table><p>在这个例子中，即使甲后续并没有投稿申请经验，其第一个投稿依然能使用主文件名，这样避免了访问 URL 时跳转到完全不相关的帖子。</p><h2 id="资产路径" tabindex="-1">资产路径 <a class="header-anchor" href="#资产路径" aria-label="Permalink to &quot;资产路径&quot;">​</a></h2><p>若一帖子引用了图片、自定义组件、CSS 等资产，则作出如下目录调整：</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>| &lt;id&gt;/</span></span>
<span class="line"><span>|-- index.md</span></span>
<span class="line"><span>|-- img1.png</span></span>
<span class="line"><span>|-- img2.png</span></span>
<span class="line"><span>|-- MyComponent.vue</span></span>
<span class="line"><span>|-- style.css</span></span>
<span class="line"><span>|-- ...</span></span></code></pre></div><p>即，不使用单个文件 <code>&lt;id&gt;.md</code>，而是使用一个目录 <code>&lt;id&gt;/</code>，在其下存放相关的资产，而帖子本身为 <code>index.md</code>。</p><h2 id="已弃用的路径格式" tabindex="-1"><s>已弃用的路径格式</s> <a class="header-anchor" href="#已弃用的路径格式" aria-label="Permalink to &quot;~~已弃用的路径格式~~&quot;">​</a></h2><div class="warning custom-block github-alert"><p class="custom-block-title">已弃用</p><p>这一节中描述的路径格式已在 <code>v3</code> 中被弃用。</p></div><p>样例：</p><ul><li><code>/grad-application/computer-science-and-engineering/[US]-15-yanxiangyi</code></li><li><code>/grad-application/finance/financial-engineering/[SG]-16-liyilin</code></li><li><code>/oversea-program/semester-program/uc_yangzonghao</code></li></ul><h3 id="路径名" tabindex="-1">路径名 <a class="header-anchor" href="#路径名" aria-label="Permalink to &quot;路径名&quot;">​</a></h3><p>路径格式为：<code>&lt;type&gt;[/&lt;subtype&gt;]/&lt;school&gt;[/&lt;major&gt;]</code>，其中</p><ul><li><code>&lt;type&gt;</code> 为帖子类别，如 <code>grad-application</code>、<code>oversea-program</code> 等。</li><li><code>&lt;subtype&gt;</code> 为可选的细分类别，如 <code>英语学习</code> 下细分 <code>TOEFL</code>、<code>GRE</code> 等。</li><li><code>&lt;school&gt;</code> 为学院名称，如 <code>data-science</code>、<code>artificial-intelligence</code> 等。</li><li><code>&lt;major&gt;</code> 为可选的专业名称，当一个院系下有多个专业时使用，如 <code>biology</code> 下的 <code>bioinformatics</code>、<code>bioscience</code> 等。</li></ul><div class="warning custom-block github-alert"><p class="custom-block-title">已弃用</p><p></p><p>这个格式已被弃用：</p><ul><li>URL 过长</li><li>创建、查找帖子困难</li><li>专业、院系的命名和层级不确定</li><li>许多专业没有或只有少数几个帖子</li></ul></div><h3 id="文件名" tabindex="-1">文件名 <a class="header-anchor" href="#文件名" aria-label="Permalink to &quot;文件名&quot;">​</a></h3><p>文件名格式为：<code>[&lt;region&gt;]-&lt;year&gt;-&lt;name&gt;</code>，其中</p><ul><li><code>&lt;region&gt;</code> 为地区代码，如 <code>US</code>、<code>CN</code>、<code>HK</code> 等</li><li><code>&lt;year&gt;</code> 为年级的后两位数字，如 2019 年入学对应 <code>19</code></li><li><code>&lt;name&gt;</code> 为姓名的全拼写，如「李小明」对应 <code>lixiaoming</code>。</li></ul><div class="warning custom-block github-alert"><p class="custom-block-title">已弃用</p><p>这个格式已被弃用，一来因其过长，二来不应在 URL 中使用 <code>[]</code> 等特殊字符。</p></div>`,31)])])}const m=t(d,[["render",c]]);export{h as __pageData,m as default};
